  children,
  initialState,
}: {
  children: React.ReactNode;
  initialState?: RootReducers;
}) => {
  return (
    <ReduxMockProvider initialState={initialState}>
      <ThemeProvider theme={theme}>{children}</ThemeProvider>
    </ReduxMockProvider>
  );
};

